// Generate shop slug from shop name
const body = $input.first().json;

const shopName = body.shopName || 'myshop';
const shopSlug = shopName
  .toLowerCase()
  .replace(/[^a-z0-9]+/g, '-')
  .replace(/^-|-$/g, '')
  .substring(0, 50);

// Generate secure temporary password
const tempPassword = 'Billed@' + Math.random().toString(36).slice(2, 12) + Math.floor(Math.random() * 100);

// Determine domain based on environment
const domain = body.env === 'production' ? 'billed.in' : 'localhost';
const siteUrl = body.env === 'production' 
  ? `https://${shopSlug}.billed.in` 
  : `http://${shopSlug}.localhost`;

return {
  json: {
    ...body,
    shopSlug,
    tempPassword,
    siteUrl,
    fullSiteName: `${shopSlug}.${domain}`,
    status: 'initiated',
    timestamp: new Date().toISOString()
  }
};

// Validate and check for duplicate sites
const data = $input.first().json;
const fs = require('fs');
const path = require('path');

const sitesPath = '/home/frappe/sites';
const fullSiteName = data.fullSiteName;

try {
  const exists = fs.existsSync(path.join(sitesPath, fullSiteName));
  if (exists) {
    return {
      json: {
        ...data,
        error: 'Site already exists',
        status: 'failed'
      }
    };
  }
  return { json: { ...data, status: 'validated' } };
} catch (e) {
  return { json: { ...data, status: 'validated', skipCheck: true } };
}

// Create user in Frappe
const data = $input.first().json;

const email = data.email;
const firstName = data.ownerName?.split(' ')[0] || 'Owner';
const lastName = data.ownerName?.split(' ').slice(1).join(' ') || '';

return {
  json: {
    ...data,
    userCommands: [
      `docker exec frappe_docker-backend-1 bench --site ${data.fullSiteName} create-user "${email}" --first-name "${firstName}" --last-name "${lastName}" --password "${data.tempPassword}"`,
      `docker exec frappe_docker-backend-1 bench --site ${data.fullSiteName} add-user-role "${email}" "System Manager"`
    ]
  }
};

